module top_module(dado, clock, habilita_escrita, saida);input [7:0] dado;
	input clock;
	input habilita_escrita;
	output reg [7:0] saida;

	  wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always@(posedge clock or posedge dbg_halt)
		if(habilita_escrita)
			saida <= dado;
		else
			saida <= 0;

endmodule
